                `,n.appendChild(v)}),S.appendChild(n)};g.seriesEnseñanza.forEach((a,n)=>{const d=document.createElement("button");d.className="tab-btn",d.textContent=a.title,n===0&&(d.classList.add("active"),e(a.videos)),d.addEventListener("click",()=>{document.querySelectorAll(".tab-btn").forEach(v=>v.classList.remove("active")),d.classList.add("active"),e(a.videos)}),y.appendChild(d)})}const w=document.getElementById("devocionales-container");if(w&&g.devocionales){w.innerHTML="",g.devocionales.forEach((u,j)=>{const z=document.createElement("article");z.className="devocional-card",z.setAttribute("data-dev-id",u.id),z.innerHTML=`
